#!/usr/bin/env node
/*
 * import-witch-trials-newspapers-from-json.js — S199
 *
 * Reads the daily Salem Oracle newspaper JSONs produced by gennewspaper
 *   ~/Development/Salem/data/json/newspapers/<YYYY-MM-DD>.json
 * and upserts them into PG `salem_witch_trials_newspapers`.
 *
 * Replaces the SalemIntelligence-mediated import path. Source of truth is
 * the on-disk JSON, regenerated by Salem Oracle. The previous chain
 * (Salem Oracle → JSON → SalemIntelligence ingest → import-1692-newspapers.js
 *  → salem_newspapers_1692 [orphan]) is no longer used.
 *
 * Idempotent. Safe to re-run.
 *
 * Usage: node import-witch-trials-newspapers-from-json.js
 */

const { Pool } = require('pg');
const fs = require('fs');
const path = require('path');
const os = require('os');

if (!process.env.DATABASE_URL) {
  try {
    const envContent = fs.readFileSync(path.resolve(__dirname, '../.env'), 'utf8');
    for (const line of envContent.split('\n')) {
      const t = line.trim();
      if (!t || t.startsWith('#')) continue;
      const eq = t.indexOf('=');
      if (eq === -1) continue;
      const k = t.slice(0, eq).trim();
      let v = t.slice(eq + 1).trim();
      if ((v.startsWith('"') && v.endsWith('"')) || (v.startsWith("'") && v.endsWith("'"))) v = v.slice(1, -1);
      if (!process.env[k]) process.env[k] = v;
    }
  } catch (_) {}
}

const NEWSPAPERS_DIR = path.join(os.homedir(), 'Development/Salem/data/json/newspapers');
const pool = new Pool({ connectionString: process.env.DATABASE_URL });

function loadJson(p) {
  try { return JSON.parse(fs.readFileSync(p, 'utf8')); } catch (_) { return null; }
}

(async () => {
  const files = fs.readdirSync(NEWSPAPERS_DIR)
    .filter(f => f.endsWith('.json') && !f.startsWith('_'));

  console.log(`Found ${files.length} newspaper JSONs in ${NEWSPAPERS_DIR}`);
  if (files.length === 0) {
    console.error('FAILED: zero newspaper JSONs — aborting');
    process.exit(1);
  }

  const upsert = `
    INSERT INTO salem_witch_trials_newspapers
      (id, date, day_of_week, long_date, crisis_phase,
       summary, lede, tts_full_text,
       events_referenced, event_count, fact_count, primary_source_count,
       data_source, confidence, verified_date, generator_model, generated_at)
    VALUES
      ($1, $2, $3, $4, $5,
       $6, $7, $8,
       $9::jsonb, $10, $11, $12,
       $13, $14, NOW(), $15, $16)
    ON CONFLICT (id) DO UPDATE SET
      date                  = EXCLUDED.date,
      day_of_week           = EXCLUDED.day_of_week,
      long_date             = EXCLUDED.long_date,
      crisis_phase          = EXCLUDED.crisis_phase,
      summary               = EXCLUDED.summary,
      lede                  = EXCLUDED.lede,
      tts_full_text         = EXCLUDED.tts_full_text,
      events_referenced     = EXCLUDED.events_referenced,
      event_count           = EXCLUDED.event_count,
      fact_count            = EXCLUDED.fact_count,
      primary_source_count  = EXCLUDED.primary_source_count,
      data_source           = EXCLUDED.data_source,
      confidence            = EXCLUDED.confidence,
      verified_date         = EXCLUDED.verified_date,
      generator_model       = EXCLUDED.generator_model,
      generated_at          = EXCLUDED.generated_at,
      updated_at            = NOW()
  `;

  let ok = 0, fail = 0;
  for (const f of files) {
    const a = loadJson(path.join(NEWSPAPERS_DIR, f));
    if (!a || !a.id || !a.date || !a.tts_full_text) {
      fail++;
      console.error(`  SKIP [${f}]: missing id/date/tts_full_text`);
      continue;
    }
    try {
      await pool.query(upsert, [
        a.id,
        a.date,
        a.day_of_week || null,
        a.long_date || null,
        Number.isInteger(a.crisis_phase) ? a.crisis_phase : 0,
        a.summary || null,
        a.lede || null,
        a.tts_full_text,
        JSON.stringify(a.events_referenced || []),
        a.event_count || 0,
        a.fact_count || 0,
        a.primary_source_count || 0,
        'salem_oracle',
        0.9,
        a.model || 'salem-village (gemma3:27b)',
        a.generated_at || null,
      ]);
      ok++;
    } catch (e) {
      fail++;
      console.error(`  FAIL [${a.id}]:`, e.message);
    }
  }

  const { rows: [{ count }] } = await pool.query(
    "SELECT COUNT(*)::int AS count FROM salem_witch_trials_newspapers WHERE deleted_at IS NULL"
  );
  console.log(`Upserted ${ok}/${files.length} (${fail} failures). Table now has ${count} active rows.`);
  await pool.end();
})().catch((e) => { console.error('FATAL:', e); process.exit(1); });
